function SwitchDemo() {
  const [isOn, setIsOn] = useState(false);

  return (
    <div>
      <label htmlFor="notif-switch">알림</label>
      <button
        id="notif-switch"
        role="switch"
        aria-checked={isOn}
        onClick={() => setIsOn(!isOn)}
        style={{ background: isOn ? '#1976d2' : '#ccc' }}
      >
        <span aria-hidden="true">{isOn ? 'ON' : 'OFF'}</span>
      </button>
    </div>
  );
}
